<header class="page-head"><div><h1>Slučajevi</h1><p>Centralni pregled svih slučajeva.</p></div><a class="button" href="/?page=case-create">+ Novi slučaj</a></header>
<form class="search" method="get"><input type="hidden" name="page" value="cases"><input name="q" value="<?= htmlspecialchars($q) ?>" placeholder="Pretraži po broju, pokojniku ili kontaktu"><button>Pretraži</button></form>
<div class="panel table-wrap"><table><thead><tr><th>Broj</th><th>Pokojnik</th><th>Kontakt</th><th>Sahrana</th><th>Mesto</th><th>Faza</th></tr></thead><tbody><?php foreach ($cases as $row): ?><tr><td><a href="/?page=case&id=<?= $row['id'] ?>"><?= htmlspecialchars($row['case_number']) ?></a></td><td><?= htmlspecialchars($row['deceased_name']) ?></td><td><?= htmlspecialchars($row['contact_name']) ?><br><small><?= htmlspecialchars($row['contact_phone']) ?></small></td><td><?= date('d.m.Y. H:i', strtotime($row['funeral_at'])) ?></td><td><?= htmlspecialchars($row['funeral_place']) ?></td><td><span class="badge"><?= htmlspecialchars($row['stage']) ?></span></td></tr><?php endforeach; ?><?php if (!$cases): ?><tr><td colspan="6">Nema pronađenih slučajeva.</td></tr><?php endif; ?></tbody></table></div>
